install(TARGETS {{targets}}
    RUNTIME DESTINATION {{runtime}}
    LIBRARY DESTINATION {{library}}
    ARCHIVE DESTINATION {{archive}}
)

MEMORY
{
  FLASH (rx)  : ORIGIN = {{flashOrigin}}, LENGTH = {{flashLength}}
  RAM   (rwx) : ORIGIN = {{ramOrigin}}, LENGTH = {{ramLength}}
}

SECTIONS
{
  .text :
  {
    KEEP(*(.isr_vector))
    *(.text*)
    *(.rodata*)
  } > FLASH

  .data :
  {
    *(.data*)
  } > RAM AT > FLASH

  .bss (NOLOAD) :
  {
    *(.bss*)
    *(COMMON)
  } > RAM
}
